import { Stack, Typography, useTheme } from "@mui/material";
import { ComponentProps } from "react";

import {
  ChartTooltip,
  ChartTooltipContent,
  ChartTooltipHeader,
} from "@dfp/react-chart";
import { CurrencyAmount } from "@dfp/react-currency-amount";
import { IconAlertSquare, IconAlertTriangle } from "@dfp/react-icons";

import { useTT } from "../../../useTT.ts";
import type { LineChartDataPoint } from "../../types/cashflow.types.ts";
import { getQualityThemeColor } from "../cashflowQuality.config.ts";

type ChartTooltipContentArgs = ComponentProps<
  typeof ChartTooltipContent<string, LineChartDataPoint>
>;

type Props = ChartTooltipContentArgs & {
  labelFormatter: (label: string | number | undefined) => string;
  currency: string;
  active: boolean;
};

const QUALITY_PREFIX: Record<LineChartDataPoint["balanceQuality"], string> = {
  CALCULATED: "calculated",
  IMPORTED: "imported",
  DERIVED: "derived",
};

const ICON_SIZE = 18;

/**
 * Custom tooltip for CashflowLineChart that shows exactly one balance row
 * at bridge points where two quality segments share a data point.
 *
 * At a bridge point, multiple series have values (the outgoing segment's real
 * value and the incoming segment's copied bridge value). Without filtering,
 * both rows would appear in the tooltip. This component keeps only the entry
 * whose dataKey prefix matches the data point's own balanceQuality, so the
 * user always sees a single, accurate row.
 */
export function CashflowLineChartTooltip({
  active,
  payload,
  label,
  labelFormatter,
  currency,
}: Props) {
  const { tt } = useTT();
  const theme = useTheme();
  const point = payload[0]?.payload;

  if (!active || !payload.length || !point) return null;

  const prefix = QUALITY_PREFIX[point.balanceQuality];
  const filteredPayload = payload.filter(
    (entry) =>
      typeof entry.dataKey === "string" && entry.dataKey.startsWith(prefix),
  );
  const displayPayload =
    filteredPayload.length > 0 ? filteredPayload : payload.slice(0, 1);

  const { balanceQuality } = point;
  const qualityColor =
    balanceQuality !== "IMPORTED"
      ? getQualityThemeColor(theme, balanceQuality)
      : undefined;

  const qualityTitle =
    balanceQuality === "DERIVED"
      ? tt("chart.inaccurateFinalBalance")
      : balanceQuality === "CALCULATED"
        ? tt("chart.calculatedFinalBalance")
        : tt("chart.endingBalance");

  const icon =
    balanceQuality === "DERIVED" ? (
      <IconAlertTriangle width={ICON_SIZE} height={ICON_SIZE} />
    ) : balanceQuality === "CALCULATED" ? (
      <IconAlertSquare width={ICON_SIZE} height={ICON_SIZE} />
    ) : null;

  const value = displayPayload[0]?.value;

  return (
    <ChartTooltip>
      <ChartTooltipHeader
        sx={{
          flexDirection: "column",
          alignItems: "stretch",
          justifyContent: "flex-start",
          gap: 0.5,
        }}
      >
        <Stack
          sx={{
            flexDirection: "row",
            alignItems: "center",
            gap: 0.5,
            color: qualityColor,
          }}
        >
          {icon}
          <Typography variant="subtitle2" sx={{ color: "inherit" }}>
            {qualityTitle}
          </Typography>
        </Stack>
        <Stack
          sx={{
            flexDirection: "row",
            justifyContent: "space-between",
            alignItems: "center",
          }}
        >
          <Typography variant="body2">{labelFormatter(label)}</Typography>
          <Typography variant="subtitle2">
            <CurrencyAmount
              value={Number(value ?? 0)}
              currency={currency}
              naturalPrecision
            />
          </Typography>
        </Stack>
      </ChartTooltipHeader>
    </ChartTooltip>
  );
}

export * from "./cashflowDataTransformers.ts";
export * from "./cashflowFormatters.ts";
export * from "./formatPeriodLabel.ts";
export * from "./useCompanyStorage.ts";
export * from "./dateUtils.ts";
