                </Typography>
              </ChartTooltipHeader>
              <Divider />
              <ChartTooltipBody sx={{ gap: 0.5 }}>
                <Typography variant="body2">
                  Income: {Number(totalIncome).toLocaleString()}
                </Typography>
                <Typography variant="body2">
                  Costs: {Number(totalCosts).toLocaleString()}
                </Typography>
              </ChartTooltipBody>
            </ChartTooltip>
          );
        },
      }}
    />
  ),
};

