import { Divider, Stack, Typography } from "@mui/material";

import { useChart } from "../chart/index.ts";
import { ChartIndicator } from "../components/index.ts";
import { ChartTooltipBody } from "./ChartTooltipBody.tsx";
import { ChartTooltipHeader } from "./ChartTooltipHeader.tsx";
import type { ChartPayloadEntry } from "./chartTooltip.types.ts";

export type ChartTooltipHeaderConfig =
  | {
      title?: string;
      label?: (label: string | number | undefined) => string;
    }
  | false;

type ChartTooltipContentProps<
  TKey extends string = string,
  TData extends Record<string, unknown> = Record<string, unknown>,
> = {
  payload: readonly ChartPayloadEntry<TKey, TData>[];
  label: string | number | undefined;
  /** Pass `false` to suppress the header. Omit to show the X-axis label. */
  header?: ChartTooltipHeaderConfig;
  formatter?: (value: number | string, dataKey: TKey) => string;
};

/**
 * Default tooltip body. Renders each payload entry with its indicator, label, and value.
 * Exported for use inside `content` render props when you want the default rows
 * alongside a custom surrounding layout.
 */
export function ChartTooltipContent<
  TKey extends string = string,
  TData extends Record<string, unknown> = Record<string, unknown>,
>({
  payload,
  label,
  header,
  formatter,
}: ChartTooltipContentProps<TKey, TData>) {
  const { config } = useChart();

  const headerTitle = header ? header.title : undefined;
  let headerLabel: string | undefined;
  if (header !== false) {
    if (header?.label) {
      headerLabel = header.label(label);
    } else if (label !== undefined) {
      headerLabel = String(label);
    }
  }
  const showHeader =
    header !== false &&
    (headerTitle !== undefined || headerLabel !== undefined);

  return (
    <>
      {showHeader && (
        <>
          <ChartTooltipHeader>
            {headerTitle !== undefined && (
              <Typography variant="body2">{headerTitle}</Typography>
            )}
            {headerLabel !== undefined && (
              <Typography variant="subtitle2">{headerLabel}</Typography>
            )}
          </ChartTooltipHeader>
          <Divider />
        </>
      )}

      <ChartTooltipBody sx={{ gap: 1 }}>
        {payload.map((entry) => {
          const key = String(entry.dataKey ?? entry.name ?? "");
          const itemConfig = config[key];

          const formattedValue =
            entry.value !== undefined
              ? formatter
                ? formatter(entry.value, key as TKey)
                : String(entry.value)
              : null;

          return (
            <Stack
              key={key}
              sx={{ flexDirection: "row", justifyContent: "space-between" }}
            >
              <Stack
                sx={{ flexDirection: "row", alignItems: "center", gap: 0.5 }}
              >
                <ChartIndicator dataKey={key} color={entry.color} />
                <Typography variant="body2">
                  {itemConfig?.label ?? entry.name}
                </Typography>
              </Stack>

              {formattedValue !== null && (
                <Typography variant="subtitle2">{formattedValue}</Typography>
              )}
            </Stack>
          );
        })}
      </ChartTooltipBody>
    </>
  );
}

