export type FormatCurrencyAmountArguments = {
  value: number;
  // ISO 4217 currency code (CZK, EUR, USD, ...)
  currency: string;
  // ISO 639-1 language code (2 letters)
  language: string;
  /**
   * How to display the sign in the output.
   * - "auto" (default): Show the minus sign for negative numbers.
   * - "never": Never show the minus sign.
   * - "always": Always show the minus sign.
   * - "exceptZero": Show the minus sign for negative numbers and the plus sign for positive numbers.
   */
  signDisplay?: Intl.NumberFormatOptions["signDisplay"];
  /**
   * How to display the currency in the output.
   * - "symbol" (default): Use a localized currency symbol such as €, £, or ¥.
   * - "code": Use the ISO currency code.
   * - "none": Do not display the currency in the output.
   */
  currencyDisplay?: "symbol" | "code" | "none";
  /**
   * Where to place the currency code relative to the amount.
   * Only applies when `currencyDisplay` is `"code"`.
   *
   * - "end" (default): e.g. "1,234.56 USD"
   * - "start": e.g. "USD 1,234.56"
   */
  currencyPosition?: "start" | "end";
  /**
   * The minimum number of fraction digits to use.
   * Node.js only supports 20 as maximum.
   */
  minimumFractionDigits?: number;
  /**
   * The maximum number of fraction digits to use.
   * Node.js only supports 20 as maximum.
   */
  maximumFractionDigits?: number | undefined;
  /**
   * The formatting notation to use.
   * - "standard" (default): Plain number formatting.
   * - "compact": Abbreviated formatting, e.g. "1.2M" or "16K".
   * - "scientific" / "engineering": Scientific notation variants.
   */
  notation?: Intl.NumberFormatOptions["notation"];
};

export const formatCurrencyAmount = (props: FormatCurrencyAmountArguments) => {
  return formatCurrencyAmountToParts(props)
    .map((part) => part.value)
    .join("");
};

export const formatCurrencyAmountRound = ({
  maximumFractionDigits = 2,
  ...rest
}: FormatCurrencyAmountArguments) =>
  formatCurrencyAmount({ maximumFractionDigits, ...rest });

export const formatCurrencyAmountCompact = ({
  minimumFractionDigits = 0,
  maximumFractionDigits = 1,
  ...rest
}: FormatCurrencyAmountArguments) =>
  formatCurrencyAmount({
    notation: "compact",
    minimumFractionDigits,
    maximumFractionDigits,
    ...rest,
  });

export const formatCurrencyAmountToParts = ({
  value,
  currency,
  language,
  signDisplay,
  currencyDisplay = "symbol",
  currencyPosition = "end",
  minimumFractionDigits = 2,
  maximumFractionDigits = 20,
  notation,
}: FormatCurrencyAmountArguments): Intl.NumberFormatPart[] => {
  const adaptedLanguage = languageTo2LettersCode(language);

  const shared = {
    signDisplay,
    minimumFractionDigits,
    maximumFractionDigits,
    notation,
  };

  if (currencyDisplay === "none") {
    return Intl.NumberFormat(adaptedLanguage, shared).formatToParts(value);
  }

  if (currencyDisplay === "code") {
    const parts = Intl.NumberFormat(adaptedLanguage, shared).formatToParts(
      value,
    );

    const currencyPart: Intl.NumberFormatPart = {
      type: "currency",
      value: currencyPosition === "start" ? `${currency} ` : ` ${currency}`,
    };

    return currencyPosition === "start"
      ? [currencyPart, ...parts]
      : [...parts, currencyPart];
  }

  return Intl.NumberFormat(languageTo2LettersCode(language), {
    ...shared,
    currency: currency,
    style: "currency",
  }).formatToParts(value);
};

export function languageTo2LettersCode(language: string): string {
  if (["en", "cs"].includes(language)) {
    return language;
  }
  return "en";
}

import type { SxProps, Theme } from "@mui/material";
import { useTranslation } from "react-i18next";

import {
  type FormatCurrencyAmountArguments,
  formatCurrencyAmount,
  formatCurrencyAmountToParts,
} from "@dfp/isomorphic-currency-amount";

import { WithSuperscriptDecimals } from "./WithSuperscriptDecimals.tsx";
import { getCurrencyPrecision, roundCurrencyAmount } from "./rounding/index.ts";

/**
 * Props shared by {@link CurrencyAmount}.
 *
 * Extends the underlying `FormatCurrencyAmountArguments` (minus `language`,
 * which is resolved from the current i18n context) and adds an optional
 * `superscriptDecimals` flag for visual formatting.
 */
type Props = Omit<FormatCurrencyAmountArguments, "language" | "currency"> & {
  /**
   * When true, displays decimal digits as superscript.
   * For example: $2,000.89 becomes $2,000 with .89 in superscript.
   */
  superscriptDecimals?: boolean;
  currency: string | undefined;
  slotProps?: {
    superscript?: {
      sx?: SxProps<Theme>;
    };
  };
  /**
   * When true, automatically derives `minimumFractionDigits` and
   * `maximumFractionDigits` from the currency's native precision
   * (`basicPrecision` in the currency enum) and pre-rounds the value.
   *
   * For example: JPY → 0 decimals, USD → 2, BHD → 3.
   *
   * Currencies with `basicPrecision: Infinity` (precious metals like XAU,
   * XAG) fall back to {@link infinityFallback} decimal places.
   *
   * When enabled, any explicit `minimumFractionDigits` / `maximumFractionDigits`
   * props are ignored.
   */
  naturalPrecision?: boolean;
  /**
   * Fallback number of decimal places used when {@link naturalPrecision} is
   * `true` and the currency's `basicPrecision` is `Infinity`.
   *
   * @default 2
   */
  infinityFallback?: number;
};

/**
 * Formats and displays a currency amount.
 *
 * By default, uses `Intl.NumberFormat` with `minimumFractionDigits: 2`,
 * preserving all significant decimal places from the input value
 * (up to `maximumFractionDigits`, default 20).
 *
 * When `naturalPrecision` is `true`, automatically derives decimal precision
 * from the currency's `basicPrecision` enum value and pre-rounds the value
 * accordingly (e.g. JPY → 0, USD → 2, BHD → 3).
 *
 * Optionally renders decimal digits as superscript text when
 * `superscriptDecimals` is `true`.
 */
export function CurrencyAmount({
  superscriptDecimals = false,
  currencyDisplay = "symbol",
  naturalPrecision = false,
  infinityFallback = 2,
  slotProps,
  ...props
}: Props) {
  const { i18n } = useTranslation();

  if (!props.currency) {
    return null;
  }

  const formatArgs = {
    language: i18n.language,
    currencyDisplay,
    ...props,
    ...(naturalPrecision
      ? toNaturalPrecision(props.currency, props.value, infinityFallback)
      : undefined),
  } as Parameters<typeof formatCurrencyAmountToParts>[0];

  if (superscriptDecimals) {
    return (
      <span>
        <WithSuperscriptDecimals
          parts={formatCurrencyAmountToParts(formatArgs)}
          slotProps={{ superscript: slotProps?.superscript }}
        />
      </span>
    );
  }

  return <>{formatCurrencyAmount(formatArgs)}</>;
}

function toNaturalPrecision(
  currency: string,
  value: number,
  infinityFallback: number,
) {
  const precision = getCurrencyPrecision(currency);
  const finitePrecision = Number.isFinite(precision)
    ? precision
    : infinityFallback;

  return {
    value: roundCurrencyAmount(currency, value),
    minimumFractionDigits: finitePrecision,
    maximumFractionDigits: finitePrecision,
  };
}

